import{_ as a,c as e,o as i,ag as t}from"./chunks/framework.Co20b0ok.js";const k=JSON.parse('{"title":"端口转发","description":"","frontmatter":{},"headers":[],"relativePath":"intranet-security/tips/端口转发 196b61af42898069b24bcd7b5b612a68.md","filePath":"intranet-security/tips/端口转发 196b61af42898069b24bcd7b5b612a68.md"}'),h={name:"intranet-security/tips/端口转发 196b61af42898069b24bcd7b5b612a68.md"};function n(p,s,o,d,l,c){return i(),e("div",null,s[0]||(s[0]=[t('<h1 id="端口转发" tabindex="-1">端口转发 <a class="header-anchor" href="#端口转发" aria-label="Permalink to &quot;端口转发&quot;">​</a></h1><h2 id="ssh-本地端口转发" tabindex="-1">SSH - 本地端口转发 <a class="header-anchor" href="#ssh-本地端口转发" aria-label="Permalink to &quot;SSH - 本地端口转发&quot;">​</a></h2><p>本地端口转发将你本地的一个端口的流量通过 <code>SSH</code> 连接转发到远程主机的某个端口。</p><p>假设你想将本地端口 <code>8080</code> 转发到远程服务器的 <code>192.168.1.100:80</code></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 8080:192.168.1.100:80</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@remote_server</span></span></code></pre></div><h2 id="ssh-远程端口转发" tabindex="-1">SSH - 远程端口转发 <a class="header-anchor" href="#ssh-远程端口转发" aria-label="Permalink to &quot;SSH - 远程端口转发&quot;">​</a></h2><p>远程端口转发将远程主机的端口流量转发到本地机器上的端口</p><p>如果你想将远程服务器的端口 <code>9090</code> 转发到本地机器的 <code>8080</code></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 9090:localhost:8080</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@remote_server</span></span></code></pre></div><p>访问远程服务器的 <code>http://remote_server:9090</code> 就相当于访问本地机器的 <code>http://localhost:8080</code></p><h2 id="ssh-动态端口转发" tabindex="-1">SSH - 动态端口转发 <a class="header-anchor" href="#ssh-动态端口转发" aria-label="Permalink to &quot;SSH - 动态端口转发&quot;">​</a></h2><p>动态端口转发将本地端口设置为 <code>SOCKS</code> 代理，通过该代理可以转发所有类型的流量</p><p>假设你想将本地端口 <code>1080</code> 设置为 <code>SOCKS</code> 代理</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -D</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1080</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@remote_server</span></span></code></pre></div><h2 id="socat-端口转发" tabindex="-1">Socat 端口转发 <a class="header-anchor" href="#socat-端口转发" aria-label="Permalink to &quot;Socat 端口转发&quot;">​</a></h2><p>在本地开启<code>9000</code>端口监听，将监听到的数据都转发到本地的<code>80</code>端口上</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./socat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TCP-LISTEN:9000,fork</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TCP4:127.0.0.1:80</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span></span></code></pre></div>',17)]))}const b=a(h,[["render",n]]);export{k as __pageData,b as default};
